body.script:
$(document).ready(function () {
    //CopyToClipboard.copy('js-copy-to-clipboard');
    MakitaModalDefault.ModalNavigation();

    const promoClosed = getExpiryPromoBar('promoBarHidden');

    if (promoClosed) {
        //Hide the promo bar
        $('.js-promo-container-wrapper').hide();

    } else {
        // Show the promo bar
        $('.js-promo-container-wrapper').show();
    }

    //Close promo bar
    $('.js-close-promo').on('click', function (ev) {
        ev.preventDefault();
        $(ev.currentTarget).parent().remove();

        setExpiryPromoBar('promoBarHidden', true, 59 * 60 * 1000); // 59 minutes

        //Scroll to top Sticky menu - If any
        if ($('#js-scroll-stick').length) {
            var dynStickyMenu = document.querySelector('#js-scroll-stick'),
                targetBottom = $('header').height();

            $(dynStickyMenu).addClass("sticky").css({ 'top': targetBottom });
        }
    });

    // Call Accordion method for the Footer menu - Mobile Only
    Reveal.show('js-show-hide-tools', true, 'js-tools-solution', 600);
    Reveal.show('js-show-hide-helpful', true, 'js-tools-helpful', 600);
    Reveal.show('js-show-hide-comnpany', true, 'js-tools-comnpany', 600);

    // Call Accordion method for the Top menu - Mobile Only
    $("[data-accordion-class]").each(function (index) {
        var submenuClass = $(this).data('accordion-class');
        var submenuId = $(this).data('reveal');

        if ((submenuClass !== "") && (submenuId !== "")) {
            Reveal.show(submenuClass, true, submenuId, 1100);
        }
    });

    var promoCarousel = 'js-promo-bar-carousel';

    if ($('#' + promoCarousel).length) {
        // Start Promo bar Carousel
        Carousel.start(promoCarousel, null, 1, 1, null, null, null, null, null, null, false, null, null, false);
        toggleCarousel('#' + promoCarousel, 900);

        // Handle window resize
        $(window).on('resize', function () {
            toggleCarousel('#' + promoCarousel, 900);
        });
    }
});

function setExpiryPromoBar(key, value, time) {
    const now = Date.now();
    const item = {
        value: value,
        expiry: now + time
    };

    localStorage.setItem(key, JSON.stringify(item));
}

function getExpiryPromoBar(key) {
    const itemStr = localStorage.getItem(key);

    if (!itemStr) {
        return null;
    }

    try {
        const item = JSON.parse(itemStr);
        const now = Date.now();

        if (now > item.expiry) {
            // clean up
            localStorage.removeItem(key);
            return null;
        }

        return item.value;

    } catch (event) {
        // handle corrupted JSON
        return null;
    }
}

// Toggle carousel according to the page width
function toggleCarousel(carousel, width) {
    const screenRes = document.documentElement.clientWidth;

    screenRes <= width ? $(carousel).slick('refresh') : $(carousel).slick('unslick');
}

var globalVar = {
    appBaseURL: 'https://makitatools.com',
    cdnBaseURL: 'https://cdn.makitatools.com/'
};


var selectedLanguage = "en-us";

window.dataLayer = window.dataLayer || [];
