(function () {
    "use strict"; // Enforces secure, modern JS parsing rules

    const pageTrackingId = crypto.randomUUID();
    const startTime = performance.now();
    const initialReferrer = document.referrer;
    const currentUrl = window.location.href;

    // Log Page Entry instantly on execution
    fetch('/Tracking/LogPageEntry', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            pageTrackingId: pageTrackingId,
            url: currentUrl,
            referrer: initialReferrer
        })
    }).catch(err => console.warn("Tracking entry failed:", err));

    //  Log Page Exit via Beacon when navigating away or closing the tab
    window.addEventListener('visibilitychange', function logExit() {
        if (document.visibilityState === 'hidden') {
            const endTime = performance.now();
            const durationSeconds = Math.round((endTime - startTime) / 1000);

            // Only send if they spent a meaningful second or more on the page
            if (durationSeconds >= 1) {
                const exitPayload = new URLSearchParams();
                exitPayload.append('pageTrackingId', pageTrackingId);
                exitPayload.append('duration', durationSeconds);
                exitPayload.append('url', currentUrl);
                exitPayload.append('referrer', initialReferrer);

                navigator.sendBeacon('/Tracking/LogPageExit', exitPayload);
            }
        }
    });

    // Outbound Link Click Tracker
    document.addEventListener("click", function (event) {
        // Find the closest anchor tag '' element from the clicked target
        const link = event.target.closest("a");

        // If it's not a link, or doesn't have an href, ignore it
        if (!link || !link.href) return;

        // Verify if the link is truly outbound (external)
        const isExternal = link.hostname !== window.location.hostname;

        if (isExternal) {
            const externalDestination = link.href;
            const clickPayload = new URLSearchParams();
            clickPayload.append('pageTrackingId', pageTrackingId);
            clickPayload.append('currentUrl', currentUrl);
            clickPayload.append('destinationUrl', externalDestination);

            // sendBeacon guarantees the browser completes the request 
            // even as it unloads the page to go to the new site
            navigator.sendBeacon('/Tracking/LogOutboundClick', clickPayload);
        }
    });

    // MODAL TRACKING ENGINE ---
    let activeModalId = null;
    let modalStartTime = null;
    let modalName = "";

    // Function to call when a modal opens
    window.trackModalOpen = function (nameOfModal) {
        activeModalId = crypto.randomUUID(); // Unique ID for this specific modal instance
        modalStartTime = performance.now();
        modalName = nameOfModal;

        // Log the virtual page view to your entry endpoint
        fetch('/Tracking/LogPageEntry', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                pageTrackingId: activeModalId, // Treat the modal as its own unique tracking track
                url: `${currentUrl}#modal: ${modalName}`, // Creates a clean virtual URL path
                referrer: currentUrl // The parent page acts as the referrer!
            })
        }).catch(err => console.warn("Modal tracking entry failed:", err));
    };

    // Function to call when a modal closes
    window.trackModalClose = function () {
        if (!activeModalId || !modalStartTime) return;
        const endTime = performance.now();
        const durationSeconds = Math.round((endTime - modalStartTime) / 1000);

        // Prepare payload for your existing LogPageExit endpoint
        const exitPayload = new URLSearchParams();
        exitPayload.append('pageTrackingId', activeModalId);
        exitPayload.append('duration', durationSeconds);
        exitPayload.append('url', `${currentUrl}#modal: ${modalName}`);
        exitPayload.append('referrer', currentUrl);

        navigator.sendBeacon('/Tracking/LogPageExit', exitPayload);

        // Reset variables for the next modal interaction
        activeModalId = null;
        modalStartTime = null;
        modalName = "";
    };

})();
